{
  "manifest_version": 3,
  "name": "GovTranslate",
  "version": "1.0.0",
  "permissions": ["storage", "activeTab", "scripting"],
  "host_permissions": ["https://api.anthropic.com/*"],
  "background": {
    "service_worker": "background.js"
  },
  "action": {
    "default_popup": "popup.html"
  },
  "content_scripts": [
    {
      "matches": ["<all_urls>"],
      "js": ["content.js"]
    }
  ]
}

// content.js
chrome.runtime.sendMessage({
  type: "TRANSLATE_SELECTION",
  text: window.getSelection().toString()
}, (response) => {
  if (response?.translatedText) {
    console.log(response.translatedText);
  }
});

// background.js
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type !== "TRANSLATE_SELECTION") return;

  (async () => {
    const { anthropicApiKey } = await chrome.storage.sync.get("anthropicApiKey");

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "x-api-key": anthropicApiKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true"
      },
      body: JSON.stringify({
        model: "claude-3-5-haiku-latest",
        max_tokens: 512,
        messages: [
          {
            role: "user",
            content: `Translate this text clearly and faithfully:\n\n${message.text}`
          }
        ]
      })
    });

    const data = await response.json();
    const translatedText = data.content?.[0]?.text ?? "";
    sendResponse({ translatedText });
  })();

  return true;
});

// content.js — robust message sending with error handling
async function requestTranslation(text, targetLanguage) {
  return new Promise((resolve, reject) => {
    const message = {
      type: 'TRANSLATE_SELECTION',
      payload: {
        text: text.slice(0, 4000), // Guard against very large selections
        targetLanguage,
        timestamp: Date.now()
      }
    };

    chrome.runtime.sendMessage(message, (response) => {
      if (chrome.runtime.lastError) {
        reject(new Error(chrome.runtime.lastError.message));
        return;
      }
      if (!response) {
        reject(new Error('No response from service worker'));
        return;
      }
      if (response.error) {
        reject(new Error(response.error));
        return;
      }
      resolve(response.translatedText);
    });
  });
}

// background.js — async message handler that keeps channel open
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type !== 'TRANSLATE_SELECTION') return false;

  handleTranslation(message.payload)
    .then(translatedText => sendResponse({ translatedText }))
    .catch(error => sendResponse({ error: error.message }));

  return true; // Signal async response
});

async function handleTranslation({ text, targetLanguage }) {
  const { anthropicApiKey } = await chrome.storage.sync.get('anthropicApiKey');
  if (!anthropicApiKey) throw new Error('API key not configured');

  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'x-api-key': anthropicApiKey,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify({
      model: 'claude-3-5-haiku-latest',
      max_tokens: 1024,
      messages: [{
        role: 'user',
        content: `Translate the following text to ${targetLanguage}. Return only the translation, no explanation:\n\n${text}`
      }]
    })
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.error?.message ?? `HTTP ${res.status}`);
  }

  const data = await res.json();
  return data.content?.[0]?.text ?? '';
}
